});

// -- Selection state --

describe("selection", () => {
  beforeEach(() => {
    addTile({ id: "t1", type: "term", x: 0, y: 0, width: 1, height: 1, zIndex: 1 });
    addTile({ id: "t2", type: "note", x: 0, y: 0, width: 1, height: 1, zIndex: 2 });
