{
  "canvasRpc": "import {
	tiles, getTile, defaultSize, snapToGrid,
} from "./canvas-state.js";

/**
 * Find a non-overlapping position on the canvas for a tile of the
 * given size. Scans on a 20 px grid within a 4000x3000 region.
 */
export function findAutoPlacement(existingTiles, width, height) {
	const CANVAS_W = 4000;
	const CANVAS_H = 3000;
	const STEP = 20;

	for (let y = 0; y <= CANVAS_H - height; y += STEP) {
		for (let x = 0; x <= CANVAS_W - width; x += STEP) {
			const overlaps = existingTiles.some((t) =>
				x < t.x + t.width &&
				x + width > t.x &&
				y < t.y + t.height &&
				y + height > t.y,
			);
			if (!overlaps) return { x, y };
		}
	}

	const last = existingTiles[existingTiles.length - 1];
	if (last) return { x: last.x + 40, y: last.y + 40 };
	return { x: 40, y: 40 };
}

/**
 * Create the canvas RPC request handler.
 *
 * Methods: tileList, tileCreate, tileRemove, tileMove, tileResize,
 *          viewportGet, viewportSet, terminalWrite, terminalRead,
 *          tileFocus, browserNavigate, browserScreenshot,
 *          browserSnapshot, browserClick, browserType,
 *          browserScroll, browserEvaluate, browserWait,
 *          browserInfo.
 */
export function createCanvasRpc({
	tileManager, viewportState, viewport, edgeIndicators,
}) {
	function respond(requestId, result) {
		window.shellApi.canvasRpcResponse({ requestId, result });
	}

	function respondError(requestId, code, message) {
		window.shellApi.canvasRpcResponse({
			requestId, error: { code, message },
		});
	}

	function requireTile(requestId, tileId) {
		const tile = getTile(tileId);
		if (!tile) {
			respondError(requestId, 3, "Tile not found");
			return null;
		}
		return tile;
	}

	function requireBrowserWcId(requestId, tileId) {
		const tile = requireTile(requestId, tileId);
		if (!tile) return null;
		if (tile.type !== "browser") {
			respondError(requestId, 4, "Tile is not a browser");
			return null;
		}
		const dom = tileManager.getTileDOMs().get(tileId);
		if (!dom || !dom.webview) {
			respondError(requestId, 4, "Browser webview not ready");
			return null;
		}
		return dom.webview.getWebContentsId();
	}

	return async function handleCanvasRpc(request) {
		const { requestId, method, params } = request;

		try {
			let result;
			switch (method) {
				case "tileList": {
					result = {
						tiles: tiles.map((t) => ({
							id: t.id,
							type: t.type,
							filePath: t.filePath,
							folderPath: t.folderPath,
							url: t.url,
							cwd: t.cwd,
							ptySessionId: t.ptySessionId,
							userTitle: t.userTitle,
							autoTitle: t.autoTitle,
							position: { x: t.x, y: t.y },
							size: { width: t.width, height: t.height },
							zIndex: t.zIndex,
						})),
					};
					break;
				}
				case "tileCreate": {
					const tileType = params.tileType || "note";
					const size = defaultSize(tileType);
					const pos = params.position
						? { x: params.position.x, y: params.position.y }
						: findAutoPlacement(tiles, size.width, size.height);

					let tile;
					if (tileType === "term") {
						tile = tileManager.createCanvasTile(
							"term", pos.x, pos.y,
						);
						tileManager.spawnTerminalWebview(tile);
					} else if (tileType === "browser") {
						tile = tileManager.createCanvasTile(
							"browser", pos.x, pos.y, { url: params.url },
						);
						tileManager.spawnBrowserWebview(tile, false);
					} else if (tileType === "pdf") {
						tile = tileManager.createFileTile(
							"pdf", pos.x, pos.y, params.filePath,
						);
					} else if (tileType === "graph") {
						const wsPath = "";
						tile = tileManager.createGraphTile(
							pos.x, pos.y, params.filePath, wsPath,
						);
					} else {
						tile = tileManager.createFileTile(
							tileType, pos.x, pos.y, params.filePath,
						);
					}
					tileManager.saveCanvasImmediate();
					result = { tileId: tile.id };
					break;
				}
				case "tileRemove": {
					if (!requireTile(requestId, params.tileId)) return;
					tileManager.closeCanvasTile(params.tileId);
					result = {};
					break;
				}
				case "tileMove": {
					const tile = requireTile(requestId, params.tileId);
					if (!tile) return;
					const mx = params.position?.x;
					const my = params.position?.y;
					if (!Number.isFinite(mx) || !Number.isFinite(my)) {
						respondError(requestId, 4, "Invalid position");
						return;
					}
					tile.x = mx;
					tile.y = my;
					snapToGrid(tile);
					tileManager.repositionAllTiles();
					tileManager.saveCanvasImmediate();
					result = {};
					break;
				}
				case "tileResize": {
					const tile = requireTile(requestId, params.tileId);
					if (!tile) return;
					const rw = params.size?.width;
					const rh = params.size?.height;
					if (!Number.isFinite(rw) || !Number.isFinite(rh)) {
						respondError(requestId, 4, "Invalid size");
						return;
					}
					tile.width = rw;
					tile.height = rh;
					snapToGrid(tile);
					tileManager.repositionAllTiles();
					tileManager.saveCanvasImmediate();
					result = {};
					break;
				}
				case "viewportGet": {
					result = {
						pan: {
							x: viewportState.panX,
							y: viewportState.panY,
						},
						zoom: viewportState.zoom,
					};
					break;
				}
				case "viewportSet": {
					if (params.pan) {
						viewportState.panX = params.pan.x;
						viewportState.panY = params.pan.y;
					}
					if (params.zoom !== undefined) {
						viewportState.zoom = params.zoom;
					}
					viewport.updateCanvas();
					tileManager.saveCanvasDebounced();
					result = {};
					break;
				}
				case "terminalWrite": {
					const tile = requireTile(requestId, params.tileId);
					if (!tile) return;
					if (tile.type !== "term") {
						respondError(requestId, 4, "Tile is not a terminal");
						return;
					}
					if (!tile.ptySessionId) {
						respondError(requestId, 4, "Terminal has no session");
						return;
					}
					window.shellApi.ptyWrite(
						tile.ptySessionId, params.input,
					);
					result = {};
					break;
				}
				case "terminalRead": {
					const tile = requireTile(requestId, params.tileId);
					if (!tile) return;
					if (tile.type !== "term") {
						respondError(requestId, 4, "Tile is not a terminal");
						return;
					}
					if (!tile.ptySessionId) {
						respondError(requestId, 4, "Terminal has no session");
						return;
					}
					const lines = params.lines ?? 50;
					const output = await window.shellApi.ptyCapture(
						tile.ptySessionId, lines,
					);
					result = { output };
					break;
				}
				case "browserNavigate": {
					const tile = requireTile(requestId, params.tileId);
					if (!tile) return;
					if (tile.type !== "browser") {
						respondError(requestId, 4, "Tile is not a browser");
						return;
					}
					const dom = tileManager.getTileDOMs().get(tile.id);
					if (!dom?.webview) {
						respondError(requestId, 4, "Browser has no webview");
						return;
					}
					const wcId = dom.webview.getWebContentsId();
					result = await window.shellApi.browserNavigate(wcId, params.url);
					tile.url = params.url;
					if (dom.urlInput) dom.urlInput.value = params.url;
					break;
				}
				case "browserScreenshot": {
					const tile = requireTile(requestId, params.tileId);
					if (!tile) return;
					if (tile.type !== "browser") {
						respondError(requestId, 4, "Tile is not a browser");
						return;
					}
					const dom = tileManager.getTileDOMs().get(tile.id);
					if (!dom?.webview) {
						respondError(requestId, 4, "Browser has no webview");
						return;
					}
					const wcId = dom.webview.getWebContentsId();
					result = await window.shellApi.browserScreenshot(wcId);
					break;
				}
				case "browserSnapshot": {
					const tile = requireTile(requestId, params.tileId);
					if (!tile) return;
					if (tile.type !== "browser") {
						respondError(requestId, 4, "Tile is not a browser");
						return;
					}
					const dom = tileManager.getTileDOMs().get(tile.id);
					if (!dom?.webview) {
						respondError(requestId, 4, "Browser has no webview");
						return;
					}
					const wcId = dom.webview.getWebContentsId();
					result = await window.shellApi.browserSnapshot(wcId);
					break;
				}
				case "browserClick": {
					const tile = requireTile(requestId, params.tileId);
					if (!tile) return;
					if (tile.type !== "browser") {
						respondError(requestId, 4, "Tile is not a browser");
						return;
					}
					const dom = tileManager.getTileDOMs().get(tile.id);
					if (!dom?.webview) {
						respondError(requestId, 4, "Browser has no webview");
						return;
					}
					const wcId = dom.webview.getWebContentsId();
					result = await window.shellApi.browserClick(wcId, params.selector);
					break;
				}
				case "browserType": {
					const tile = requireTile(requestId, params.tileId);
					if (!tile) return;
					if (tile.type !== "browser") {
						respondError(requestId, 4, "Tile is not a browser");
						return;
					}
					const dom = tileManager.getTileDOMs().get(tile.id);
					if (!dom?.webview) {
						respondError(requestId, 4, "Browser has no webview");
						return;
					}
					const wcId = dom.webview.getWebContentsId();
					result = await window.shellApi.browserType(
						wcId, params.selector, params.text,
					);
					break;
				}
				case "browserScroll": {
					const wcId = requireBrowserWcId(
						requestId, params.tileId,
					);
					if (wcId == null) return;
					result = await window.shellApi.browserScroll(
						wcId, params.x ?? 0, params.y ?? 0,
					);
					break;
				}
				case "browserEvaluate": {
					const wcId = requireBrowserWcId(
						requestId, params.tileId,
					);
					if (wcId == null) return;
					result = await window.shellApi.browserEvaluate(
						wcId, params.expression,
					);
					break;
				}
				case "browserWait": {
					const wcId = requireBrowserWcId(
						requestId, params.tileId,
					);
					if (wcId == null) return;
					result = await window.shellApi.browserWait(
						wcId, params.timeout,
					);
					break;
				}
				case "browserInfo": {
					const wcId = requireBrowserWcId(
						requestId, params.tileId,
					);
					if (wcId == null) return;
					result = await window.shellApi.browserInfo(wcId);
					break;
				}
				case "tileFocus": {
					const ids = params.tileIds;
					if (!Array.isArray(ids) || ids.length === 0) {
						respondError(
							requestId, 4,
							"tileIds must be a non-empty array",
						);
						return;
					}
					const focusTiles = [];
					for (const id of ids) {
						const t = getTile(id);
						if (!t) {
							respondError(
								requestId, 3, `Tile not found: ${id}`,
							);
							return;
						}
						focusTiles.push(t);
					}
					edgeIndicators.panToTiles(focusTiles);
					result = {};
					break;
				}
				default: {
					respondError(
						requestId, -32601,
						`Unknown method: ${method}`,
					);
					return;
				}
			}
			respond(requestId, result);
		} catch (err) {
			respondError(
				requestId, -32603,
				err.message || "Internal error",
			);
		}
	};
}
",
  "tileInteractions": "import { snapToGrid } from "./canvas-state.js";

const MIN_SIZES = {
  term: { width: 200, height: 120 },
  note: { width: 200, height: 120 },
  code: { width: 200, height: 120 },
  image: { width: 80, height: 80 },
  graph: { width: 300, height: 250 },
};

const CLICK_THRESHOLD = 3;

/**
 * Attach drag behavior to a tile's title bar.
 * Supports single-tile drag, group drag (when tile is in a
 * multi-tile selection), and Shift+click toggling.
 *
 * @param {HTMLElement} titleBar
 * @param {import('./canvas-state.js').Tile} tile
 * @param {object} opts
 * @param {object} opts.viewport - { panX, panY, zoom } (read live)
 * @param {() => void} opts.onUpdate
 * @param {(ws: Array<{webview: HTMLElement}>) => void} opts.disablePointerEvents
 * @param {(ws: Array<{webview: HTMLElement}>) => void} opts.enablePointerEvents
 * @param {() => Array<{webview: HTMLElement}>} opts.getAllWebviews
 * @param {() => null | Array<{tile: object, container: HTMLElement, startX: number, startY: number}>} opts.getGroupDragContext
 * @param {(tileId: string) => void} opts.onShiftClick
 * @param {() => boolean} [opts.isSpaceHeld] - when true, suppress drag (canvas is panning)
 * @param {HTMLElement} [opts.contentOverlay] - secondary drag surface over tile content
 */
export function attachDrag(titleBar, tile, {
  viewport,
  onUpdate,
  disablePointerEvents,
  enablePointerEvents,
  getAllWebviews,
  getGroupDragContext,
  onShiftClick,
  onFocus,
  isSpaceHeld,
  contentOverlay,
}) {
  function startDrag(e, { deferFocus = false } = {}) {
    if (e.button !== 0) return;
    if (isSpaceHeld?.()) return;
    e.preventDefault();
    if (!deferFocus && onFocus) onFocus(tile.id, e);

    const startMX = e.clientX;
    const startMY = e.clientY;
    const startTX = tile.x;
    const startTY = tile.y;
    const startPanX = viewport.panX;
    const startPanY = viewport.panY;
    const shiftHeld = e.shiftKey;

    const groupCtx = getGroupDragContext();
    const isGroupDrag = groupCtx !== null && groupCtx.length > 1;

    const webviews = getAllWebviews();
    disablePointerEvents(webviews);

    const container = titleBar.closest(".canvas-tile");
    container.classList.add("tile-dragging");
    if (isGroupDrag) {
      for (const entry of groupCtx) {
        entry.container.classList.add("tile-dragging");
      }
    }

    let moved = false;
    let lastMX = startMX;
    let lastMY = startMY;

    function applyDrag(mx, my) {
      const panDX = viewport.panX - startPanX;
      const panDY = viewport.panY - startPanY;
      const dx = (mx - startMX - panDX) / viewport.zoom;
      const dy = (my - startMY - panDY) / viewport.zoom;

      if (isGroupDrag) {
        for (const entry of groupCtx) {
          entry.tile.x = entry.startX + dx;
          entry.tile.y = entry.startY + dy;
        }
      } else {
        tile.x = startTX + dx;
        tile.y = startTY + dy;
      }
      onUpdate();
    }

    function onMove(e) {
      lastMX = e.clientX;
      lastMY = e.clientY;
      const dist = Math.hypot(lastMX - startMX, lastMY - startMY);
      if (dist >= CLICK_THRESHOLD) moved = true;
      applyDrag(lastMX, lastMY);
    }

    function onWheel() {
      applyDrag(lastMX, lastMY);
    }

    function onUp(e) {
      document.removeEventListener("mousemove", onMove);
      document.removeEventListener("mouseup", onUp);
      document.removeEventListener("wheel", onWheel);
      enablePointerEvents(webviews);

      if (shiftHeld && !moved) {
        container.classList.remove("tile-dragging");
        if (isGroupDrag) {
          for (const entry of groupCtx) {
            entry.container.classList.remove("tile-dragging");
          }
        }
        onShiftClick(tile.id);
        return;
      }

      if (deferFocus && !moved && onFocus) {
        onFocus(tile.id, e);
      }

      container.classList.remove("tile-dragging");
      if (isGroupDrag) {
        for (const entry of groupCtx) {
          entry.container.classList.remove("tile-dragging");
          snapToGrid(entry.tile);
        }
      } else {
        snapToGrid(tile);
      }
      onUpdate();
    }

    document.addEventListener("mousemove", onMove);
    document.addEventListener("mouseup", onUp);
    document.addEventListener("wheel", onWheel, { passive: true });
  }

  titleBar.addEventListener("mousedown", (e) => startDrag(e));

  if (contentOverlay) {
    contentOverlay.addEventListener("mousedown", (e) => {
      startDrag(e, { deferFocus: true });
    });
  }
}

/**
 * Attach marquee (rubber-band) selection to the canvas element.
 *
 * @param {HTMLElement} canvasEl
 * @param {object} opts
 * @param {object} opts.viewport - { panX, panY, zoom } (read live)
 * @param {() => Array<import('./canvas-state.js').Tile>} opts.tiles
 * @param {(ids: Set<string>) => void} opts.onSelectionChange
 * @param {() => boolean} opts.isShiftHeld
 * @param {() => boolean} opts.isSpaceHeld
 * @param {() => Array<{webview: HTMLElement}>} opts.getAllWebviews
 */
export function attachMarquee(canvasEl, {
  viewport,
  tiles,
  onSelectionChange,
  isShiftHeld,
  isSpaceHeld,
  getAllWebviews,
}) {
  const tileLayer = canvasEl.querySelector("#tile-layer");
  const gridCanvas = canvasEl.querySelector("#grid-canvas");

  canvasEl.addEventListener("mousedown", (e) => {
    if (e.button !== 0) return;
    // Ignore if Space is held (pan gesture)
    if (isSpaceHeld()) return;
    // Only trigger on clicks directly on the canvas background
    if (
      e.target !== canvasEl &&
      e.target !== tileLayer &&
      e.target !== gridCanvas
    ) return;

    e.preventDefault();
    if (document.activeElement) document.activeElement.blur();

    const webviews = getAllWebviews();
    for (const w of webviews) w.webview.style.pointerEvents = "none";

    const startSX = e.clientX;
    const startSY = e.clientY;

    const marquee = document.createElement("div");
    marquee.className = "selection-marquee";
    marquee.style.position = "fixed";
    marquee.style.left = `${startSX}px`;
    marquee.style.top = `${startSY}px`;
    marquee.style.width = "0px";
    marquee.style.height = "0px";
    document.body.appendChild(marquee);

    let moved = false;

    function onMove(e) {
      const curSX = e.clientX;
      const curSY = e.clientY;
      const dist = Math.hypot(curSX - startSX, curSY - startSY);
      if (dist >= CLICK_THRESHOLD) moved = true;

      const left = Math.min(startSX, curSX);
      const top = Math.min(startSY, curSY);
      const width = Math.abs(curSX - startSX);
      const height = Math.abs(curSY - startSY);

      marquee.style.left = `${left}px`;
      marquee.style.top = `${top}px`;
      marquee.style.width = `${width}px`;
      marquee.style.height = `${height}px`;
    }

    function onUp(e) {
      document.removeEventListener("mousemove", onMove);
      document.removeEventListener("mouseup", onUp);
      marquee.remove();
      for (const w of webviews) w.webview.style.pointerEvents = "";

      if (!moved) {
        // Click on empty canvas — clear selection
        onSelectionChange(new Set());
        return;
      }

      // Compute marquee rect in canvas coordinates
      const curSX = e.clientX;
      const curSY = e.clientY;
      const mLeft = Math.min(startSX, curSX);
      const mTop = Math.min(startSY, curSY);
      const mRight = Math.max(startSX, curSX);
      const mBottom = Math.max(startSY, curSY);

      // Convert viewport-relative pointer coords into canvas coords.
      const viewerRect = canvasEl.getBoundingClientRect();
      const toCanvas = (sx, sy) => ({
        x: (sx - viewerRect.left - viewport.panX) / viewport.zoom,
        y: (sy - viewerRect.top - viewport.panY) / viewport.zoom,
      });

      const cTL = toCanvas(mLeft, mTop);
      const cBR = toCanvas(mRight, mBottom);

      // AABB hit-test against all tiles
      const hitIds = new Set();
      for (const t of tiles()) {
        const tRight = t.x + t.width;
        const tBottom = t.y + t.height;
        if (
          t.x < cBR.x &&
          tRight > cTL.x &&
          t.y < cBR.y &&
          tBottom > cTL.y
        ) {
          hitIds.add(t.id);
        }
      }

      if (isShiftHeld()) {
        // Additive — merge with existing selection handled by caller
        // Pass the new hits; caller unions with current selection
        onSelectionChange(hitIds);
      } else {
        onSelectionChange(hitIds);
      }
    }

    document.addEventListener("mousemove", onMove);
    document.addEventListener("mouseup", onUp);
  });
}

