			},
			enablePointerEvents: (wvs) => {
				for (const w of wvs) {
					w.webview.style.pointerEvents = "";
				}
			},
			getAllWebviews,
			getGroupDragContext: () => {
				if (
					!isSelected(tile.id) ||
					getSelectedTiles().length <= 1
				) {
					return null;
				}
				return getSelectedTiles().map((t) => ({
					tile: t,
					container: tileDOMs.get(t.id)?.container,
					startX: t.x,
					startY: t.y,
				}));
			},
