import {
  addComponent,
  addEntity,
  getAllEntities,
  getRelationTargets,
  hasComponent,
  query,
  removeComponent,
  removeEntity,
} from "bitecs";
import {
  world,
  WorldPos,
  Content,
  Selected,
  FocusedTile,
  StripCell,
  SplitNode,
  TabNode,
  SlotIndex,
  WindowTag,
  GroupMembership,
  ChildOf,
  CONTENT_KIND,
  contentKindToTileType,
  tileTypeToContentKind,
  isCanvasTileKind,
  generateId as worldGenerateId,
  noteZIndex,
  nextTileZIndex,
  eidByPublicId,
  publicIdByEid,
  setPublicIdForEid,
  clearEntityMetadata,
} from "./world.js";

export const tiles = [];

const tileByEid = new Map();
const orderedTileEids = [];
const nativeSplice = Array.prototype.splice;
let syncingTilesArray = false;

const DEFAULT_TILE_SIZES = {
  term: { width: 400, height: 500 },
  note: { width: 440, height: 540 },
  code: { width: 440, height: 540 },
  image: { width: 280, height: 280 },
  graph: { width: 600, height: 500 },
  browser: { width: 800, height: 650 },
  pdf: { width: 600, height: 800 },
};

const IMAGE_EXTENSIONS = new Set([
  ".png", ".jpg", ".jpeg", ".gif", ".svg", ".webp",
]);

const GRID_CELL = 20;

function normalizeNumber(value, fallback = 0) {
  return Number.isFinite(value) ? value : fallback;
}

function normalizeMaybeString(value) {
  return typeof value === "string" && value.length > 0 ? value : null;
}

function readMaybeString(store, eid) {
  const value = store[eid];
  return value == null ? undefined : value;
}

function writeMaybeString(store, eid, value) {
  store[eid] = normalizeMaybeString(value);
}

function syncTilesArray() {
  syncingTilesArray = true;
  nativeSplice.call(
    tiles,
    0,
    tiles.length,
    ...orderedTileEids
      .map((eid) => tileByEid.get(eid))
      .filter(Boolean),
  );
  syncingTilesArray = false;
}

function removeOrderedTileEid(eid) {
  const index = orderedTileEids.indexOf(eid);
  if (index !== -1) {
    orderedTileEids.splice(index, 1);
  }
}

function isPanelPublicId(publicId) {
  return typeof publicId === "string" && publicId.startsWith("panel:");
}

function defineField(target, key, getter, setter) {
  Object.defineProperty(target, key, {
    enumerable: true,
    configurable: false,
    get: getter,
    set: setter,
  });
}

function createTileFacade(eid) {
  const tile = {};

  Object.defineProperty(tile, "__eid", {
    enumerable: false,
    configurable: false,
    get: () => eid,
  });

  defineField(tile, "id", () => Content.publicId[eid], (value) => {
    setPublicIdForEid(eid, value);
  });
  defineField(tile, "type", () => contentKindToTileType(Content.kind[eid]), (value) => {
    Content.kind[eid] = tileTypeToContentKind(value);
  });
  defineField(tile, "x", () => normalizeNumber(WorldPos.x[eid]), (value) => {
    WorldPos.x[eid] = normalizeNumber(value);
  });
  defineField(tile, "y", () => normalizeNumber(WorldPos.y[eid]), (value) => {
    WorldPos.y[eid] = normalizeNumber(value);
  });
  defineField(tile, "width", () => normalizeNumber(WorldPos.w[eid]), (value) => {
    WorldPos.w[eid] = normalizeNumber(value);
  });
  defineField(tile, "height", () => normalizeNumber(WorldPos.h[eid]), (value) => {
    WorldPos.h[eid] = normalizeNumber(value);
  });
  defineField(tile, "zIndex", () => normalizeNumber(WorldPos.zIndex[eid], 1), (value) => {
    const zIndex = normalizeNumber(value, 1);
    WorldPos.zIndex[eid] = zIndex;
    noteZIndex(zIndex);
  });

  for (const key of [
    "filePath",
    "folderPath",
    "workspacePath",
    "url",
    "cwd",
    "ptySessionId",
    "userTitle",
    "autoTitle",
  ]) {
    defineField(tile, key, () => readMaybeString(Content[key], eid), (value) => {
      writeMaybeString(Content[key], eid, value);
    });
  }

  return tile;
}

function ensureTileFacade(eid) {
  let tile = tileByEid.get(eid);
  if (!tile) {
    tile = createTileFacade(eid);
    tileByEid.set(eid, tile);
  }
  return tile;
}

function registerCanvasTile(eid) {
  if (!orderedTileEids.includes(eid)) {
    orderedTileEids.push(eid);
  }
  ensureTileFacade(eid);
  syncTilesArray();
}

function unregisterCanvasTile(eid) {
  removeOrderedTileEid(eid);
  tileByEid.delete(eid);
  syncTilesArray();
}

function assignWorldPos(eid, tile) {
  WorldPos.x[eid] = normalizeNumber(tile.x);
  WorldPos.y[eid] = normalizeNumber(tile.y);
  WorldPos.w[eid] = normalizeNumber(tile.width, DEFAULT_TILE_SIZES.note.width);
  WorldPos.h[eid] = normalizeNumber(tile.height, DEFAULT_TILE_SIZES.note.height);
  const zIndex = Number.isFinite(tile.zIndex) ? tile.zIndex : nextTileZIndex();
  WorldPos.zIndex[eid] = zIndex;
  noteZIndex(zIndex);
}

function assignContent(eid, tile) {
  Content.kind[eid] = tileTypeToContentKind(tile.type);
  setPublicIdForEid(eid, tile.id || worldGenerateId());
  writeMaybeString(Content.filePath, eid, tile.filePath);
  writeMaybeString(Content.folderPath, eid, tile.folderPath);
  writeMaybeString(Content.workspacePath, eid, tile.workspacePath);
  writeMaybeString(Content.url, eid, tile.url);
  writeMaybeString(Content.cwd, eid, tile.cwd);
  writeMaybeString(Content.ptySessionId, eid, tile.ptySessionId);
  writeMaybeString(Content.userTitle, eid, tile.userTitle);
  writeMaybeString(Content.autoTitle, eid, tile.autoTitle);
}

function resolveTileEid(input) {
  if (!input) return null;
  if (typeof input === "string") {
    return eidByPublicId.get(input) ?? null;
  }
  if (typeof input === "object" && typeof input.id === "string") {
    return eidByPublicId.get(input.id) ?? input.__eid ?? null;
  }
  return null;
}

function getCanvasTileEids() {
  return query(world, [WorldPos, Content]).filter((eid) => isCanvasTileKind(Content.kind[eid]));
}

function removeTileByEid(eid) {
  const publicId = publicIdByEid.get(eid) ?? Content.publicId[eid];
  if (hasComponent(world, eid, Selected)) {
    removeComponent(world, eid, Selected);
  }
  if (hasComponent(world, eid, FocusedTile)) {
    removeComponent(world, eid, FocusedTile);
  }
  unregisterCanvasTile(eid);
  clearEntityMetadata(eid);
  removeEntity(world, eid);
  if (typeof publicId === "string") {
    eidByPublicId.delete(publicId);
  }
}

tiles.splice = function splice(start, deleteCount, ...items) {
  if (syncingTilesArray) {
    return nativeSplice.call(this, start, deleteCount, ...items);
  }
  if (items.length > 0) {
    throw new Error("Direct insertion into tiles is unsupported; use addTile().");
  }
  const actualStart = start < 0 ? Math.max(this.length + start, 0) : Math.min(start, this.length);
  const actualDeleteCount = deleteCount == null
    ? this.length - actualStart
    : Math.max(0, Math.min(deleteCount, this.length - actualStart));
  const removed = this.slice(actualStart, actualStart + actualDeleteCount);
  for (const tile of removed) {
    const eid = resolveTileEid(tile);
    if (eid != null) {
      removeTileByEid(eid);
    }
  }
  return removed;
};

/** @param {'term' | 'note' | 'code' | 'image' | 'graph' | 'browser' | 'pdf'} type */
export function defaultSize(type) {
  return { ...DEFAULT_TILE_SIZES[type] };
}

/** Snap tile position and size to the minor grid. */
export function snapToGrid(tile) {
  tile.x = Math.round(tile.x / GRID_CELL) * GRID_CELL;
  tile.y = Math.round(tile.y / GRID_CELL) * GRID_CELL;
  tile.width = Math.round(tile.width / GRID_CELL) * GRID_CELL;
  tile.height = Math.round(tile.height / GRID_CELL) * GRID_CELL;
}

export function generateId() {
  return worldGenerateId();
}

export function addTile(tile) {
  const eid = addEntity(world);
  addComponent(world, eid, WorldPos);
  addComponent(world, eid, Content);
  assignWorldPos(eid, tile);
  assignContent(eid, tile);
  registerCanvasTile(eid);
  return ensureTileFacade(eid);
}

export function removeTile(id) {
  const eid = resolveTileEid(id);
  if (eid == null) return;
  removeTileByEid(eid);
}

export function getTile(id) {
  const eid = resolveTileEid(id);
  if (eid == null || !tileByEid.has(eid)) {
    return null;
  }
  return tileByEid.get(eid);
}

export function bringToFront(tile) {
  const eid = resolveTileEid(tile);
  if (eid == null) return;
  WorldPos.zIndex[eid] = nextTileZIndex();
}

/** @param {string} id */
export function selectTile(id) {
  const eid = resolveTileEid(id);
  if (eid == null) return;
  addComponent(world, eid, Selected);
}

/** @param {string} id */
export function deselectTile(id) {
  const eid = resolveTileEid(id);
  if (eid == null || !hasComponent(world, eid, Selected)) return;
  removeComponent(world, eid, Selected);
}

/** @param {string} id */
export function toggleTileSelection(id) {
  if (isSelected(id)) {
    deselectTile(id);
  } else {
    selectTile(id);
  }
}

export function clearSelection() {
  for (const eid of query(world, [Selected])) {
    removeComponent(world, eid, Selected);
  }
}

/** @param {string} id */
export function isSelected(id) {
  const eid = resolveTileEid(id);
  return eid != null && hasComponent(world, eid, Selected);
}

/** @returns {Array<object>} */
export function getSelectedTiles() {
  return getCanvasTileEids()
    .filter((eid) => hasComponent(world, eid, Selected))
    .map((eid) => ensureTileFacade(eid));
}

/** @returns {{ x: number, y: number }} */
function tileCenter(tile) {
  return { x: tile.x + tile.width / 2, y: tile.y + tile.height / 2 };
}

/**
 * Returns the nearest tile in the given cardinal direction from fromId,
 * using a 120° forward cone filter (±60° from the axis).
 * @param {string|null} fromId - ID of focused tile, or null to use originX/Y
 * @param {'left'|'right'|'up'|'down'} direction
 * @param {number} [originX=0] - Canvas-space X when fromId is null
 * @param {number} [originY=0] - Canvas-space Y when fromId is null
 * @returns {object|null}
 */
export function getNearestTileInDirection(fromId, direction, originX = 0, originY = 0) {
  const from = fromId ? getTile(fromId) : null;
  const fc = from ? tileCenter(from) : { x: originX, y: originY };

  const axisVec = {
    right: { dx: 1, dy: 0 },
    left: { dx: -1, dy: 0 },
    down: { dx: 0, dy: 1 },
    up: { dx: 0, dy: -1 },
  }[direction];

  const CONE_HALF = Math.PI / 3;

  const candidates = getCanvasTileEids()
    .filter((eid) => Content.publicId[eid] !== fromId)
    .map((eid) => {
      const tile = ensureTileFacade(eid);
      const tc = tileCenter(tile);
      const dx = tc.x - fc.x;
      const dy = tc.y - fc.y;
      const dot = dx * axisVec.dx + dy * axisVec.dy;
      if (dot <= 0) return null;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist === 0) return null;
      if (Math.acos(dot / dist) > CONE_HALF) return null;
      return { tile, dist };
    })
    .filter(Boolean);

  if (!candidates.length) return null;
  candidates.sort((a, b) => a.dist - b.dist);
  return candidates[0].tile;
}

/** @returns {object | null} */
export function tileAtPoint(cx, cy) {
  const sorted = [...tiles].sort((a, b) => b.zIndex - a.zIndex);
  for (const tile of sorted) {
    if (
      cx >= tile.x && cx < tile.x + tile.width &&
      cy >= tile.y && cy < tile.y + tile.height
    ) {
      return tile;
    }
  }
  return null;
}

export function inferTileType(filePath) {
  const ext = filePath.slice(filePath.lastIndexOf(".")).toLowerCase();
  if (ext === ".md") return "note";
  if (ext === ".pdf") return "pdf";
  if (IMAGE_EXTENSIONS.has(ext)) return "image";
  return "code";
}

function serializeContent(eid) {
  const content = {
    kind: Content.kind[eid],
    publicId: Content.publicId[eid],
  };
  for (const key of [
    "filePath",
    "folderPath",
    "workspacePath",
    "url",
    "cwd",
    "ptySessionId",
    "userTitle",
    "autoTitle",
  ]) {
    const value = Content[key][eid];
    if (value != null) {
      content[key] = value;
    }
  }
  return content;
}

function serializeEntity(eid) {
  const components = {};

  if (hasComponent(world, eid, Content)) {
    components.Content = serializeContent(eid);
  }

  if (hasComponent(world, eid, WorldPos)) {
    components.WorldPos = {
      x: normalizeNumber(WorldPos.x[eid]),
      y: normalizeNumber(WorldPos.y[eid]),
      w: normalizeNumber(WorldPos.w[eid]),
      h: normalizeNumber(WorldPos.h[eid]),
      zIndex: normalizeNumber(WorldPos.zIndex[eid], 1),
    };
  }

  if (hasComponent(world, eid, Selected)) {
    components.Selected = true;
  }
  if (hasComponent(world, eid, FocusedTile)) {
    components.FocusedTile = true;
  }
  if (hasComponent(world, eid, StripCell)) {
    components.StripCell = {
      column: normalizeNumber(StripCell.column[eid]),
      row: normalizeNumber(StripCell.row[eid]),
    };
  }
  if (hasComponent(world, eid, SplitNode)) {
    components.SplitNode = {
      dir: normalizeNumber(SplitNode.dir[eid]),
      ratio: normalizeNumber(SplitNode.ratio[eid], 0.5),
    };
  }
  if (hasComponent(world, eid, TabNode)) {
    components.TabNode = true;
  }
  if (hasComponent(world, eid, SlotIndex)) {
    components.SlotIndex = {
      index: normalizeNumber(SlotIndex.index[eid]),
    };
  }
  if (hasComponent(world, eid, WindowTag)) {
    components.WindowTag = true;
  }
  if (hasComponent(world, eid, GroupMembership)) {
    components.GroupMembership = {
      ids: Array.from(GroupMembership.ids[eid] ?? []),
    };
  }

  const parents = getRelationTargets(world, eid, ChildOf);
  if (parents.length > 0) {
    components.ChildOf = parents[0];
  }

  return { eid, components };
}

export function serializeWorldState(viewport) {
  return {
    version: 2,
    world: {
      entities: getAllEntities(world).map((eid) => serializeEntity(eid)),
      viewport: {
        panX: normalizeNumber(viewport.panX),
        panY: normalizeNumber(viewport.panY),
        zoom: normalizeNumber(viewport.zoom, 1),
      },
    },
  };
}

function clearRuntimeWorldForRestore() {
  for (const eid of [...orderedTileEids]) {
    removeTileByEid(eid);
  }
  for (const eid of getAllEntities(world)) {
    const publicId = publicIdByEid.get(eid) ?? Content.publicId[eid];
    if (isPanelPublicId(publicId)) {
      if (hasComponent(world, eid, Selected)) {
        removeComponent(world, eid, Selected);
      }
      if (hasComponent(world, eid, FocusedTile)) {
        removeComponent(world, eid, FocusedTile);
      }
      continue;
    }
    if (publicId) {
      clearEntityMetadata(eid);
    }
    removeEntity(world, eid);
  }
  syncTilesArray();
}

function applySerializedEntity(eid, serialized) {
  const { components = {} } = serialized;
  const content = components.Content;
  const worldPos = components.WorldPos;

  if (content) {
    addComponent(world, eid, Content);
    Content.kind[eid] = normalizeNumber(content.kind, CONTENT_KIND.note);
    setPublicIdForEid(eid, content.publicId ?? `entity:${eid}`);
    for (const key of [
      "filePath",
      "folderPath",
      "workspacePath",
      "url",
      "cwd",
      "ptySessionId",
      "userTitle",
      "autoTitle",
    ]) {
      writeMaybeString(Content[key], eid, content[key]);
    }
  }

  if (worldPos) {
    addComponent(world, eid, WorldPos);
    WorldPos.x[eid] = normalizeNumber(worldPos.x);
    WorldPos.y[eid] = normalizeNumber(worldPos.y);
    WorldPos.w[eid] = normalizeNumber(worldPos.w, DEFAULT_TILE_SIZES.note.width);
    WorldPos.h[eid] = normalizeNumber(worldPos.h, DEFAULT_TILE_SIZES.note.height);
    WorldPos.zIndex[eid] = normalizeNumber(worldPos.zIndex, 1);
    noteZIndex(WorldPos.zIndex[eid]);
  }

  if (components.Selected) {
    addComponent(world, eid, Selected);
  }
  if (components.FocusedTile) {
    addComponent(world, eid, FocusedTile);
  }
  if (components.StripCell) {
    addComponent(world, eid, StripCell);
    StripCell.column[eid] = normalizeNumber(components.StripCell.column);
    StripCell.row[eid] = normalizeNumber(components.StripCell.row);
  }
  if (components.SplitNode) {
    addComponent(world, eid, SplitNode);
    SplitNode.dir[eid] = normalizeNumber(components.SplitNode.dir);
    SplitNode.ratio[eid] = normalizeNumber(components.SplitNode.ratio, 0.5);
  }
  if (components.TabNode) {
    addComponent(world, eid, TabNode);
  }
  if (components.SlotIndex) {
    addComponent(world, eid, SlotIndex);
    SlotIndex.index[eid] = normalizeNumber(components.SlotIndex.index);
  }
  if (components.WindowTag) {
    addComponent(world, eid, WindowTag);
  }
  if (components.GroupMembership) {
    addComponent(world, eid, GroupMembership);
    GroupMembership.ids[eid] = new Set(components.GroupMembership.ids ?? []);
  }

  if (content && isCanvasTileKind(Content.kind[eid])) {
    registerCanvasTile(eid);
  }
}

export function restoreWorldState(serializedEntities) {
  clearRuntimeWorldForRestore();

  const eidMap = new Map();
  const pendingRelations = [];

  for (const serialized of serializedEntities ?? []) {
    const publicId = serialized?.components?.Content?.publicId;
    const existingEid = publicId ? eidByPublicId.get(publicId) : null;
    const eid = existingEid ?? addEntity(world);

    eidMap.set(serialized.eid, eid);
    applySerializedEntity(eid, serialized);

    if (serialized?.components?.ChildOf != null) {
      pendingRelations.push([eid, serialized.components.ChildOf]);
    }
  }

  for (const [eid, savedParentEid] of pendingRelations) {
    const parentEid = eidMap.get(savedParentEid);
    if (parentEid != null) {
      addComponent(world, eid, ChildOf(parentEid));
    }
  }

  syncTilesArray();
  return tiles;
}

