import { readFile, writeFile, rename, mkdir } from "node:fs/promises";
import { existsSync } from "node:fs";
import { join } from "node:path";
import { tmpdir } from "node:os";
import * as crypto from "node:crypto";
import { COLLAB_DIR } from "./paths";

const STATE_DIR = COLLAB_DIR;
const STATE_FILE = join(STATE_DIR, "canvas-state.json");

const TILE_KIND_BY_TYPE = {
  term: 0,
  note: 1,
  code: 2,
  image: 3,
  graph: 4,
  browser: 5,
  pdf: 6,
} as const;

const TYPE_BY_TILE_KIND = new Map(
  Object.entries(TILE_KIND_BY_TYPE).map(([type, kind]) => [kind, type]),
);

interface TileState {
  id: string;
  type: keyof typeof TILE_KIND_BY_TYPE;
  x: number;
  y: number;
  width: number;
  height: number;
  filePath?: string;
  folderPath?: string;
  url?: string | null;
  workspacePath?: string;
  cwd?: string;
  ptySessionId?: string;
  userTitle?: string;
  autoTitle?: string;
  zIndex: number;
}

interface RendererCanvasState {
  version: 1;
  tiles: TileState[];
  viewport: {
    centerX: number;
    centerY: number;
    zoom: number;
  };
}

interface ContentState {
  kind: number;
  publicId: string;
  filePath?: string | null;
  folderPath?: string | null;
  workspacePath?: string | null;
  url?: string | null;
  cwd?: string | null;
  ptySessionId?: string | null;
  userTitle?: string | null;
  autoTitle?: string | null;
}

interface WorldPosState {
  x: number;
  y: number;
  w: number;
  h: number;
  zIndex: number;
}

interface SerializedEntity {
  eid: number;
  components: {
    Content?: ContentState;
    WorldPos?: WorldPosState;
    ChildOf?: number | null;
    [key: string]: unknown;
  };
}

interface SerializedCanvasState {
  version: 2;
  world: {
    entities: SerializedEntity[];
    viewport: {
      centerX: number;
      centerY: number;
      zoom: number;
    };
  };
}

function sanitizeCoord(v: unknown): number {
  return typeof v === "number" && Number.isFinite(v) ? v : 0;
}

function sanitizeZoom(v: unknown): number {
  return typeof v === "number" && Number.isFinite(v) && v > 0 ? v : 1;
}

function sanitizeMaybeString(v: unknown): string | null {
  return typeof v === "string" && v.length > 0 ? v : null;
}

function sanitizePositiveNumber(v: unknown, fallback: number): number {
  return typeof v === "number" && Number.isFinite(v) && v > 0 ? v : fallback;
}

function makePanelEntity(
  eid: number,
  kind: number,
  publicId: string,
): SerializedEntity {
  return {
    eid,
    components: {
      Content: {
        kind,
        publicId,
      },
      ChildOf: null,
    },
  };
}

function tileToEntity(tile: TileState, eid: number): SerializedEntity {
  return {
    eid,
    components: {
      Content: {
        kind: TILE_KIND_BY_TYPE[tile.type] ?? TILE_KIND_BY_TYPE.note,
        publicId: tile.id || `tile:${eid}`,
        filePath: sanitizeMaybeString(tile.filePath),
        folderPath: sanitizeMaybeString(tile.folderPath),
        workspacePath: sanitizeMaybeString(tile.workspacePath),
        url: sanitizeMaybeString(tile.url),
        cwd: sanitizeMaybeString(tile.cwd),
        ptySessionId: sanitizeMaybeString(tile.ptySessionId),
        userTitle: sanitizeMaybeString(tile.userTitle),
        autoTitle: sanitizeMaybeString(tile.autoTitle),
      },
      WorldPos: {
        x: sanitizeCoord(tile.x),
        y: sanitizeCoord(tile.y),
        w: sanitizePositiveNumber(tile.width, 1),
        h: sanitizePositiveNumber(tile.height, 1),
        zIndex: sanitizeCoord(tile.zIndex),
      },
      ChildOf: null,
    },
  };
}

function entityToTile(entity: SerializedEntity): TileState | null {
  const content = entity.components?.Content;
  const worldPos = entity.components?.WorldPos;
  if (!content || !worldPos) return null;

  const type = TYPE_BY_TILE_KIND.get(content.kind);
  if (!type) return null;

  return {
    id: content.publicId,
    type,
    x: sanitizeCoord(worldPos.x),
    y: sanitizeCoord(worldPos.y),
    width: sanitizePositiveNumber(worldPos.w, 1),
    height: sanitizePositiveNumber(worldPos.h, 1),
    filePath: content.filePath ?? undefined,
    folderPath: content.folderPath ?? undefined,
    url: content.url ?? undefined,
    workspacePath: content.workspacePath ?? undefined,
    cwd: content.cwd ?? undefined,
    ptySessionId: content.ptySessionId ?? undefined,
    userTitle: content.userTitle ?? undefined,
    autoTitle: content.autoTitle ?? undefined,
    zIndex: sanitizeCoord(worldPos.zIndex),
  };
}

function normalizeEntity(entity: SerializedEntity): SerializedEntity {
  const content = entity.components?.Content;
  const worldPos = entity.components?.WorldPos;

  const normalized: SerializedEntity = {
    eid: sanitizeCoord(entity.eid),
    components: {
      ChildOf: entity.components?.ChildOf == null
        ? null
        : sanitizeCoord(entity.components.ChildOf),
    },
  };

  if (content) {
    normalized.components.Content = {
      kind: sanitizeCoord(content.kind),
      publicId: content.publicId || `entity:${sanitizeCoord(entity.eid)}`,
      filePath: sanitizeMaybeString(content.filePath),
      folderPath: sanitizeMaybeString(content.folderPath),
      workspacePath: sanitizeMaybeString(content.workspacePath),
      url: sanitizeMaybeString(content.url),
      cwd: sanitizeMaybeString(content.cwd),
      ptySessionId: sanitizeMaybeString(content.ptySessionId),
      userTitle: sanitizeMaybeString(content.userTitle),
      autoTitle: sanitizeMaybeString(content.autoTitle),
    };
  }

  if (worldPos) {
    normalized.components.WorldPos = {
      x: sanitizeCoord(worldPos.x),
      y: sanitizeCoord(worldPos.y),
      w: sanitizePositiveNumber(worldPos.w, 1),
      h: sanitizePositiveNumber(worldPos.h, 1),
      zIndex: sanitizeCoord(worldPos.zIndex),
    };
  }

  for (const [key, value] of Object.entries(entity.components ?? {})) {
    if (
      key === "Content" ||
      key === "WorldPos" ||
      key === "ChildOf"
    ) {
      continue;
    }
    normalized.components[key] = value;
  }

  return normalized;
}

function normalizeV2(state: SerializedCanvasState): SerializedCanvasState {
  return {
    version: 2,
    world: {
      entities: (state.world?.entities ?? []).map(normalizeEntity),
      viewport: {
        centerX: sanitizeCoord(state.world?.viewport?.centerX),
        centerY: sanitizeCoord(state.world?.viewport?.centerY),
        zoom: sanitizeZoom(state.world?.viewport?.zoom),
      },
    },
  };
}

function convertLegacyToV2(state: RendererCanvasState): SerializedCanvasState {
  const entities: SerializedEntity[] = [
    makePanelEntity(1, 7, "panel:nav"),
    makePanelEntity(2, 8, "panel:agent"),
    ...state.tiles.map((tile, index) => tileToEntity(tile, index + 3)),
  ];

  return {
    version: 2,
    world: {
      entities,
      viewport: {
        centerX: sanitizeCoord(state.viewport?.centerX),
        centerY: sanitizeCoord(state.viewport?.centerY),
        zoom: sanitizeZoom(state.viewport?.zoom),
      },
    },
  };
}

function convertV2ToRendererState(state: SerializedCanvasState): RendererCanvasState {
  return {
    version: 1,
    tiles: state.world.entities
      .map((entity) => entityToTile(entity))
      .filter((tile): tile is TileState => tile !== null),
    viewport: {
      centerX: sanitizeCoord(state.world.viewport.centerX),
      centerY: sanitizeCoord(state.world.viewport.centerY),
      zoom: sanitizeZoom(state.world.viewport.zoom),
    },
  };
}

function toPersistedState(state: unknown): SerializedCanvasState {
  if (
    state &&
    typeof state === "object" &&
    (state as SerializedCanvasState).version === 2 &&
    (state as SerializedCanvasState).world
  ) {
    return normalizeV2(state as SerializedCanvasState);
  }

  return convertLegacyToV2(state as RendererCanvasState);
}

export async function loadState(): Promise<RendererCanvasState | null> {
  try {
    const raw = await readFile(STATE_FILE, "utf-8");
    const state = JSON.parse(raw) as RendererCanvasState | SerializedCanvasState;
    if (state.version === 1) {
      return convertV2ToRendererState(convertLegacyToV2(state));
    }
    if (state.version === 2) {
      return convertV2ToRendererState(normalizeV2(state));
    }
    return null;
  } catch {
    return null;
  }
}

export async function saveState(state: unknown): Promise<void> {
  if (!existsSync(STATE_DIR)) {
    await mkdir(STATE_DIR, { recursive: true });
  }
  const tmp = join(
    tmpdir(),
    `canvas-state-${crypto.randomUUID()}.json`,
  );
  const json = JSON.stringify(toPersistedState(state), null, 2);
  await writeFile(tmp, json, "utf-8");
  await rename(tmp, STATE_FILE);
}

