const cmd = `set -euo pipefail
cd /Users/alexander/Projects/surface-shell/collab-electron
printf '== git status ==\n'
git status --short
printf '\n== rg analytics/updater ==\n'
rg -n 'posthog|PostHog|analytics|trackEvent|electron-updater|updateManager|setupUpdateIPC|update-pill|AnalyticsProvider' src/ package.json || true
printf '\n== rg canvas-state import sites ==\n'
rg -n 'from "\\./canvas-state"|from "\\./canvas-state\\.js"' src/ || true
printf '\n== node bitecs import ==\n'
node --input-type=module <<'EOF'
import('bitecs').then((m) => {
  console.log(Object.keys(m).slice(0, 10));
}).catch((err) => {
  console.error(err);
  process.exit(1);
});
EOF
printf '\n== bun run build ==\n'
bun run build
printf '\n== bun test ==\n'
bun test 2>&1 | tee /tmp/current-test.log || true
printf '\n== unexpected fail lines ==\n'
grep -iE '(^|\\W)fail' /tmp/current-test.log | grep -viE 'sidecar/(client|server)\\.test|canvas-viewport\\.test|panel-manager\\.test' || true
`, out = await Bash({ command: cmd, cwd: '/Users/alexander/Projects/surface-shell/collab-electron', timeout: 900 });
console.log(JSON.stringify(out));

